module top_module(
  input Vin,
  input Vth,
  input clk,
  input reset,
  output rst_out
);reg voltage_monitor;

  always @ (posedge clk or negedge reset) begin
    if (!reset) begin
      voltage_monitor <= 0;
    end else begin
      if (Vin < Vth) begin
        voltage_monitor <= 1;
      end else begin
        voltage_monitor <= 0;
      end
    end
  end

  assign rst_out = voltage_monitor;

endmodule
